def count_substring_occurrences(text, sub):
    if len(sub) == 0:
        return 0
    if len(sub) > len(text):
        return 0
    count = 0
    i = 0
    limit = len(text) - len(sub) + 1
    while i < limit:
        if text[i:i+len(sub)] == sub:
            count = count + 1
        i = i + 1
    return count
