def top_n_words(text, n):
    counts = {}
    for w in text.split():
        if w in counts:
            counts[w] = counts[w] + 1
        else:
            counts[w] = 1
    temp = []
    for k, v in counts.items():
        # dodajemy krotki (wartość, klucz)
        temp.append((v, k))
    # sortujemy od największego do najmniejszego
    sorted_temp = sorted(temp, reverse=True)
    # bierzemy pierwsze n i zamieniamy z powrotem na (word, count)
    result = []
    for val, key in sorted_temp[:n]:
        result.append((key, val))
    return result
```

